import urllib.request, json, base64, os
token = os.environ["GITHUB_TOKEN"]
repo = "azmartone67/dchub-backend"
path = "wire_permits.py"
content_b64 = """"""
req = urllib.request.Request(
    f"https://api.github.com/repos/{repo}/contents/{path}",
    headers={"Authorization": f"token {token}", "Accept": "application/vnd.github.v3+json"}
)
sha = None
try:
    r = urllib.request.urlopen(req, timeout=10)
    sha = json.loads(r.read()).get("sha")
except: pass
body = {"message": "Add wire_permits.py", "content": content_b64}
if sha:
    body["sha"] = sha
req2 = urllib.request.Request(
    f"https://api.github.com/repos/{repo}/contents/{path}",
    data=json.dumps(body).encode(), method="PUT",
    headers={"Authorization": f"token {token}", "Accept": "application/vnd.github.v3+json", "Content-Type": "application/json"}
)
r2 = urllib.request.urlopen(req2, timeout=30)
result = json.loads(r2.read())
print(f"Pushed: {result['content']['name']} sha={result['content']['sha'][:8]}")
